import { useState } from "react";

const WINNING_LINES = [
  [0, 1, 2],
  [3, 4, 5],
  [6, 7, 8],
  [0, 3, 6],
  [1, 4, 7],
  [2, 5, 8],
  [0, 4, 8],
  [2, 4, 6],
];

function findWinner(board) {
  for (const [a, b, c] of WINNING_LINES) {
    if (board[a] && board[a] === board[b] && board[a] === board[c]) {
      return board[a];
    }
  }

  return null;
}

export default function TicTacToe() {
  const [board, setBoard] = useState(Array(9).fill(""));
  const [player, setPlayer] = useState("❌");

  const winner = findWinner(board);

  function play(index) {
    if (board[index] || winner) return;

    const nextBoard = [...board];
    nextBoard[index] = player;

    setBoard(nextBoard);
    setPlayer(player === "❌" ? "⭕" : "❌");
  }

  function reset() {
    setBoard(Array(9).fill(""));
    setPlayer("❌");
  }

  return (
    <main>
      <h1>⭕ Tic Tac Toe ❌</h1>

      <p>{winner ? `${winner} Wins! 🎉` : `Turn: ${player}`}</p>

      <table
        style={{
          margin: "0 auto",
          borderCollapse: "collapse",
        }}
      >
        <tbody>
          {[0, 1, 2].map(row => (
            <tr key={row}>
              {[0, 1, 2].map(col => {
                const index = row * 3 + col;

                return (
                  <td
                    key={col}
                    style={{
                      border: "2px solid",
                      padding: 0,
                    }}
                  >
                    <button
                      onClick={() => play(index)}
                      style={{
                        width: "4rem",
                        height: "4rem",
                        border: "none",
                        background: "none",
                        fontSize: "2rem",
                      }}
                    >
                      {board[index]}
                    </button>
                  </td>
                );
              })}
            </tr>
          ))}
        </tbody>
      </table>

      <p>
        <button onClick={reset}>Play Again</button>
      </p>
    </main>
  );
}
